UPDATE gameRules SET details = '{"links":[{"url":"http://mahjong-europe.org/portal/images/docs/Riichi-rules-2025-EN.pdf","label":"Офіційні правила EMA 2025 (PDF)"}],"rules":[{"rule":"Кількість гравців","value":"4"},{"rule":"Стартові очки","value":"0 (EMA)"},{"rule":"Чомбо","value":"20,000 очок після ума","tooltip":{"label":"Чомбо","content":"Штраф 20,000 очок після розрахунку ума за порушення правил гри."}},{"rule":"Очки продовження","value":"3x100","tooltip":{"label":"Хонба","content":"Стандартна"}},{"rule":"Червоні п''ятірки","value":"❌"},{"rule":"Пріоритет","value":"рон → перший","tooltip":{"label":"Пріоритет","content":"Рон завжди має пріоритет. Далі той, хто заколив перший."}},{"rule":"Аґарі яме","value":"❌","tooltip":{"label":"Аґарі яме","content":"Гра продовжується до кінця ханчану (раунду), навіть якщо хтось з гравців досяг цільового рахунку."}},{"rule":"Банкрутство","value":"❌","tooltip":{"label":"Банкрутство","content":"≤ 0: Гра закінчується, коли рахунок гравця досягає нуля (або менше).\n\n< 0: Гра закінчується, коли рахунок гравця стає від''ємним. Гра продовжується, коли гравець має рівно нуль очок."}},{"rule":"Округлення до манґану","value":"✅","tooltip":{"label":"Округлення до манґану","content":"4 хан 30 фу коштує як манґан"}},{"rule":"Підрахований якуман","value":"❌"},{"rule":"Накладання якуманів","value":"❌"},{"rule":"Ріічі без наступного ходу","value":"✅"},{"rule":"Подвійне ріічі","value":"2️⃣"},{"rule":"Наґаші манґан","value":"❌"},{"rule":"Подвійний якуман","value":"❌"},{"rule":"Подвійний вітер","value":"2 фу"},{"rule":"Ума","value":"15 / 5 / -5 / -15","tooltip":{"label":"Ума 15/5","content":"Фіксована ума:\n  15 / 5 / -5 / -15"}}]}' WHERE id = 4;
UPDATE gameRules SET details = '{"links":[{"url":"https://riichi.wiki/Mahjong_Soul","label":"Mahjong Soul на Riichi Wiki"}],"rules":[{"rule":"Кількість гравців","value":"4"},{"rule":"Стартові очки","value":"25,000"},{"rule":"Ума","value":"15 / 5 / -5 / -15","tooltip":{"label":"Ума 15/5","content":"Фіксована ума:\n  1-й: +15\n  2-й: +5\n  3-й: -5\n  4-й: -15"}},{"rule":"Тай-брейк ума","value":"За вітром","tooltip":{"label":"Тай-брейк за вітром","content":"При однаковому рахунку вищу позицію отримує гравець з меншим номером вітру (схід → південь → захід → північ)"}},{"rule":"Червоні п''ятірки","value":"3 (по одній на масть)"},{"rule":"Відкритий таняо (куітан)","value":"✅","tooltip":{"label":"Куітан","content":"Дозволено збирати таняо (всі прості) у відкритій руці"}},{"rule":"Атодзуке","value":"✅","tooltip":{"label":"Атодзуке","content":"Дозволено виграти, навіть якщо яку з''являється лише завдяки виграшному тайлу"}},{"rule":"Куікае (підміна)","value":"❌","tooltip":{"label":"Куікае","content":"Заборонено скидати тайл, який щойно використовувався для чі/пон"}},{"rule":"Подвійний вітер","value":"4 фу"},{"rule":"Подвійний / потрійний рон","value":"✅","tooltip":{"label":"Подвійний рон","content":"При кількох ронах — депозити ріічі отримує гравець, найближчий за чергою до того, хто скинув (атамахане)"}},{"rule":"Хонба","value":"3x100"},{"rule":"Ренчан","value":"Поки дилер виграє","tooltip":{"label":"Ренчан","content":"При подвійному роні: дилерство зберігається, якщо дилер виграв, інакше переходить.\n\nПри наґаші манґан: зберігається, якщо дилер у темпай, інакше переходить."}},{"rule":"Наґаші манґан","value":"✅"},{"rule":"Продовження матчу (енчьосен)","value":"✅","tooltip":{"label":"Енчьосен","content":"Якщо після останнього раунду жоден гравець не досяг 30,000 очок, гра продовжується додатковими раундами"}},{"rule":"Банкрутство (тобі)","value":"< 0","tooltip":{"label":"Банкрутство","content":"Гра закінчується, коли рахунок гравця стає від''ємним (< 0).\n\nГра продовжується, коли гравець має рівно нуль очок."}},{"rule":"Кандора — закритий кан","value":"Відразу","tooltip":{"label":"Кандора — закритий кан","content":"Новий індикатор дори перевертається відразу після оголошення закритого кану"}},{"rule":"Кандора — відкритий кан","value":"Після","tooltip":{"label":"Кандора — відкритий кан","content":"Новий індикатор дори перевертається після завершення ходу (скиду тайлу)"}},{"rule":"Закритий кан під час ріічі","value":"✅ (з обмеженнями)","tooltip":{"label":"Закритий кан під час ріічі","content":"Дозволено за двох умов:\n1. Тайл для кану витягнуто безпосередньо\n2. Очікування не змінюється після кану"}},{"rule":"Залишок ріічі депозитів","value":"1-му місцю"},{"rule":"Абортивні нічиї","value":"Суфу, Сукан, Кюшу, Суча","tooltip":{"label":"Абортивні нічиї","content":"Суфу ренда — 4 однакові вітри на першому скиді\nСукан наґаре — 4 кани різними гравцями\nКюшу кюхай — 9 різних благородних на першому ході\nСуча ріічі — усі 4 гравці оголосили ріічі"}},{"rule":"Санчахо (рон трьох)","value":"❌","tooltip":{"label":"Санчахо","content":"Потрійний рон (3 гравці оголошують рон одночасно) не призводить до абортивної нічиї. Усі три рони зараховуються."}},{"rule":"Пінфу","value":"Цумо 20 фу, Рон 30 фу","tooltip":{"label":"Пінфу","content":"Цумо: рахується як 20 фу (без 10 фу за цумо)\nРон: рахується як 30 фу"}},{"rule":"Чітойцу","value":"25 фу","tooltip":{"label":"Чітойцу","content":"Завжди 25 фу, незалежно від складу пар"}},{"rule":"Іппацу + Ріншян","value":"❌","tooltip":{"label":"Іппацу + Ріншян","content":"Іппацу та Хайтей не можуть комбінуватися з Ріншян кайхо"}},{"rule":"Кокуші — відкритий кан","value":"✅","tooltip":{"label":"Кокуші — закритий кан","content":"Дозволено перехопити (рон) чужий закритий кан, якщо є готова рука на кокуші мусо"}},{"rule":"Чюрен — відкритий кан","value":"❌","tooltip":{"label":"Чюрен — закритий кан","content":"Не дозволено перехоплювати чужий закритий кан для чюрен пото"}},{"rule":"Секінін бараі (пао)","value":"Дайсанґен, Дайсуші","tooltip":{"label":"Секінін бараі (пао)","content":"Відповідальність за виплату:\n— Дайсанґен: гравець, що віддав тайл для 3-го пону драконів\n— Дайсуші: гравець, що віддав тайл для 4-го понгу вітрів\n\nПри композитному якумані — відповідальність розділяється окремо за кожен якуман"}},{"rule":"Композитний якуман","value":"✅","tooltip":{"label":"Композитний якуман","content":"Дозволено комбінувати кілька якуманів в одній руці.\n\nОсобливість Тенхо: дилер починає з 14 тайлів, тому будь-який тайл може вважатися виграшним. Це означає, що Тенхо завжди комбінується з подвійними варіантами якуманів (Суанко танкі, Кокуші 13-wait, Чюрен 9-wait) = потрійний якуман."}}]}' WHERE id = 5;
UPDATE gameRules SET details = '{"links":[{"url":"https://riichi.wiki/Mahjong_Soul#3P-Mahjong","label":"Mahjong Soul Sanma на Riichi Wiki"}],"rules":[{"rule":"Кількість гравців","value":"3"},{"rule":"Стартові очки","value":"35,000"},{"rule":"Цільові очки","value":"40,000","tooltip":{"label":"Цільові очки","content":"Якщо після останнього раунду жоден гравець не досяг 40,000 очок, гра продовжується додатковими раундами (енчьосен)"}},{"rule":"Ума","value":"15 / 0 / -15","tooltip":{"label":"Ума 15/0/-15","content":"Фіксована ума:\n  1-й: +15\n  2-й: ±0\n  3-й: -15"}},{"rule":"Тай-брейк ума","value":"За вітром","tooltip":{"label":"Тай-брейк за вітром","content":"При однаковому рахунку вищу позицію отримує гравець з меншим номером вітру (схід → південь → захід)"}},{"rule":"Червоні п''ятірки","value":"2 (🀝 та 🀤)"},{"rule":"Видалені тайли","value":"2–8 манзу","tooltip":{"label":"Видалені тайли","content":"Тайли від 2 до 8 манзу не використовуються.\n\nЧерез це саншоку (змішана потрійна послідовність) неможлива.\n\nКоли індикатор дори — 1 манзу, дорою є 9 манзу."}},{"rule":"Хонба","value":"3x200","tooltip":{"label":"Хонба","content":"Кожна паличка хонба додає 200 очок (замість 100 у 4-гравцевому маджонзі)"}},{"rule":"Штраф за нотен","value":"2,000"},{"rule":"Тайлів рінсян","value":"8"},{"rule":"Чі","value":"❌","tooltip":{"label":"Чі заборонено","content":"У санма не можна оголошувати чі. Дозволені лише пон і кан."}},{"rule":"Північ (кіта/пей)","value":"Нукідора","tooltip":{"label":"Нукідора (кіта)","content":"Північ можна викласти як замінну дору (нукідора/пей). Це дає +1 хан, аналогічно червоній п''ятірці.\n\nВиграш рукою з рінсян тайлу від заміни Півночі зараховується як Рінсян кайхо."}},{"rule":"Рінсян від кіта","value":"✅","tooltip":{"label":"Ріншян від кіта","content":"Коли гравець замінює Північ і тягне тайл з ріншян — виграш цим тайлом рахується як Рінсян кайхо (яку)"}},{"rule":"Рон на кіта","value":"✅ (без чанкан)","tooltip":{"label":"Рон на кіта","content":"Можна оголосити рон, коли інший гравець замінює Північ, навіть без якумана.\n\nАле яку Чанкан НЕ зараховується — потрібна інша яку для виграшу."}},{"rule":"Кіта після пон","value":"❌","tooltip":{"label":"Кіта після пон","content":"Не можна замінювати Північ відразу після оголошення пон"}},{"rule":"Кіта скасовує","value":"Іппацу, Чіхо, Кюшу, Дабурі","tooltip":{"label":"Кіта скасовує","content":"Заміна Півночі вважається дією виклику, тому скасовує:\n— Іппацу\n— Чіхо (благословення землі)\n— Кюшу кюхай (9 термінальних)\n— Дабуру ріічі (подвійне ріічі)"}},{"rule":"Кіта та фурітен","value":"Не впливає","tooltip":{"label":"Кіта та фурітен","content":"Якщо гравець очікує на Північ, заміна Півночі іншим гравцем не створює фурітен"}},{"rule":"Північ як яку","value":"❌ (отакадзе)","tooltip":{"label":"Північ як яку","content":"Північ у руці вважається отакадзе (гостьовий вітер). Триплет Півночі НЕ дає 1 хан як якухай."}},{"rule":"Саншоку","value":"❌ (немає манзу)"},{"rule":"Дора після 1 манзу","value":"9 манзу"},{"rule":"Абортивні нічиї","value":"Сукан, Кюшу"},{"rule":"Суфу / Суча","value":"❌ (3 гравці)"},{"rule":"Підрахунок очок","value":"Цумо-лосс (ранковані)","tooltip":{"label":"Цумо-лосс","content":"За замовчуванням у рангових матчах. Переможець втрачає дохід від місця Півночі при цумо.\n\nТаблиця очок ідентична 4-гравцевому маджонгу.\n\nАльтернатива (для дружніх матчів): Розподіл Півночі — дохід від місця Півночі ділиться порівну між іншими гравцями (округлення вгору до сотень).\n\nПриклад (Розподіл): Не-дилер, 40 фу 3 хан:\n— 4P базис: дилер 2600, не-дилер 1300\n— Північ платить 1300, половина = 650 → 700\n— Дилер: 2600 + 700 = 3300\n— Не-дилер: 1300 + 700 = 2000"}}]}' WHERE id = 6;
UPDATE gameRules SET details = '{"rules":[{"rule":"Кількість гравців","value":"4"},{"rule":"Стартові очки","value":"25,000"},{"rule":"Ума","value":"15 / 5 / -5 / -15","tooltip":{"label":"Ума 15/5","content":"Фіксована ума:\n  1-й: +15\n  2-й: +5\n  3-й: -5\n  4-й: -15"}},{"rule":"Тай-брейк ума","value":"Порівну","tooltip":{"label":"Тай-брейк за вітром","content":"При однаковому рахунку вищу позицію отримує гравець з меншим номером вітру (схід → південь → захід → північ)"}},{"rule":"Червоні п''ятірки","value":"3 (по одній на масть)"},{"rule":"Відкритий таняо (куітан)","value":"✅","tooltip":{"label":"Куітан","content":"Дозволено збирати таняо (всі прості) у відкритій руці"}},{"rule":"Атодзуке","value":"✅","tooltip":{"label":"Атодзуке","content":"Дозволено виграти, навіть якщо яку з''являється лише завдяки виграшному тайлу"}},{"rule":"Куікае (підміна)","value":"❌","tooltip":{"label":"Куікае","content":"Заборонено скидати тайл, який щойно використовувався для чі/пон"}},{"rule":"Подвійний вітер","value":"2 фу"},{"rule":"Подвійний / потрійний рон","value":"✅","tooltip":{"label":"Подвійний рон","content":"При кількох ронах — депозити ріічі отримує гравець, найближчий за чергою до того, хто скинув (атамахане)"}},{"rule":"Хонба","value":"3x100"},{"rule":"Ренчан","value":"Поки дилер виграє","tooltip":{"label":"Ренчан","content":"При подвійному роні: дилерство зберігається, якщо дилер виграв, інакше переходить.\n\nПри наґаші манґан: зберігається, якщо дилер у темпай, інакше переходить."}},{"rule":"Наґаші манґан","value":"✅"},{"rule":"Продовження матчу (енчьосен)","value":"✅","tooltip":{"label":"Енчьосен","content":"Якщо після останнього раунду жоден гравець не досяг 30,000 очок, гра продовжується додатковими раундами"}},{"rule":"Банкрутство (тобі)","value":"< 0","tooltip":{"label":"Банкрутство","content":"Гра закінчується, коли рахунок гравця стає від''ємним (< 0).\n\nГра продовжується, коли гравець має рівно нуль очок."}},{"rule":"Кандора — закритий кан","value":"Відразу","tooltip":{"label":"Кандора — закритий кан","content":"Новий індикатор дори перевертається відразу після оголошення закритого кану"}},{"rule":"Кандора — відкритий кан","value":"Відразу","tooltip":{"label":"Кандора — відкритий кан","content":"Новий індикатор дори перевертається після завершення ходу (скиду тайлу)"}},{"rule":"Закритий кан під час ріічі","value":"✅ (з обмеженнями)","tooltip":{"label":"Закритий кан під час ріічі","content":"Дозволено за двох умов:\n1. Тайл для кану витягнуто безпосередньо\n2. Очікування не змінюється після кану"}},{"rule":"Залишок ріічі депозитів","value":"1-му місцю"},{"rule":"Абортивні нічиї","value":"❌","tooltip":{"label":"Абортивні нічиї","content":"Суфу ренда — 4 однакові вітри на першому скиді\nСукан наґаре — 4 кани різними гравцями\nКюшу кюхай — 9 різних благородних на першому ході\nСуча ріічі — усі 4 гравці оголосили ріічі"}},{"rule":"Санчахо (рон трьох)","value":"❌","tooltip":{"label":"Санчахо","content":"Потрійний рон (3 гравці оголошують рон одночасно) не призводить до абортивної нічиї. Усі три рони зараховуються."}},{"rule":"Пінфу","value":"Цумо 20 фу, Рон 30 фу","tooltip":{"label":"Пінфу","content":"Цумо: рахується як 20 фу (без 10 фу за цумо)\nРон: рахується як 30 фу"}},{"rule":"Чітойцу","value":"25 фу","tooltip":{"label":"Чітойцу","content":"Завжди 25 фу, незалежно від складу пар"}},{"rule":"Іппацу + Ріншян","value":"❌","tooltip":{"label":"Іппацу + Ріншян","content":"Іппацу та Хайтей не можуть комбінуватися з Ріншян кайхо"}},{"rule":"Кокуші — відкритий кан","value":"✅","tooltip":{"label":"Кокуші — закритий кан","content":"Дозволено перехопити (рон) чужий закритий кан, якщо є готова рука на кокуші мусо"}},{"rule":"Чюрен — відкритий кан","value":"❌","tooltip":{"label":"Чюрен — закритий кан","content":"Не дозволено перехоплювати чужий закритий кан для чюрен пото"}},{"rule":"Секінін бараі (пао)","value":"Дайсанґен, Дайсуші","tooltip":{"label":"Секінін бараі (пао)","content":"Відповідальність за виплату:\n— Дайсанґен: гравець, що віддав тайл для 3-го пону драконів\n— Дайсуші: гравець, що віддав тайл для 4-го понгу вітрів\n\nПри композитному якумані — відповідальність розділяється окремо за кожен якуман"}},{"rule":"Композитний якуман","value":"✅","tooltip":{"label":"Композитний якуман","content":"Дозволено комбінувати кілька якуманів в одній руці.\n\nОсобливість Тенхо: дилер починає з 14 тайлів, тому будь-який тайл може вважатися виграшним. Це означає, що Тенхо завжди комбінується з подвійними варіантами якуманів (Суанко танкі, Кокуші 13-wait, Чюрен 9-wait) = потрійний якуман."}},{"rule":"Ренхо","value":"Якуман","tooltip":{"label":"Ренхо","content":"Рон на першому колі до свого ходу"}},{"rule":"Кіріаґе манґан","value":"✅","tooltip":{"label":"Кіріаґе манґан","content":"4 Хан 30 фу завжди манґан"}},{"rule":"Пріорітет","value":"Рон -> кан/пон/чі хто перший."}]}' WHERE id = 7;
