UPDATE gameRules SET details = '{"rules":[{"rule":"Кількість гравців","value":"4"},{"rule":"Стартові очки","value":"25,000"},{"rule":"Ума","value":"15 / 5 / -5 / -15","tooltip":{"label":"Ума 15/5","content":"Фіксована ума:\n  1-й: +15\n  2-й: +5\n  3-й: -5\n  4-й: -15"}},{"rule":"Тай-брейк ума","value":"Ділиться","tooltip":{"label":"Тай-брейк ума ділиться","content":"При однаковому рахунку ума та місце діляться"}},{"rule":"Червоні п''ятірки","value":"3 (по одній на масть)"},{"rule":"Відкритий таняо (куітан)","value":"✅","tooltip":{"label":"Куітан","content":"Дозволено збирати таняо (всі прості) у відкритій руці"}},{"rule":"Атодзуке","value":"✅","tooltip":{"label":"Атодзуке","content":"Дозволено виграти, навіть якщо яку з''являється лише завдяки виграшному тайлу"}},{"rule":"Куікае (підміна)","value":"❌","tooltip":{"label":"Куікае","content":"Заборонено скидати тайл, який щойно використовувався для чі/пон"}},{"rule":"Подвійний вітер","value":"2 фу"},{"rule":"Подвійний / потрійний рон","value":"✅","tooltip":{"label":"Подвійний рон","content":"При кількох ронах — депозити ріічі отримує гравець, найближчий за чергою до того, хто скинув (атамахане)"}},{"rule":"Хонба","value":"3x100"},{"rule":"Ренчан","value":"Поки дилер виграє","tooltip":{"label":"Ренчан","content":"При подвійному роні: дилерство зберігається, якщо дилер виграв, інакше переходить.\n\nПри наґаші манґан: зберігається, якщо дилер у темпай, інакше переходить."}},{"rule":"Наґаші манґан","value":"✅"},{"rule":"Продовження матчу (енчьосен)","value":"✅","tooltip":{"label":"Енчьосен","content":"Якщо після останнього раунду жоден гравець не досяг 30,000 очок, гра продовжується додатковими раундами"}},{"rule":"Банкрутство (тобі)","value":"< 0","tooltip":{"label":"Банкрутство","content":"Гра закінчується, коли рахунок гравця стає від''ємним (< 0).\n\nГра продовжується, коли гравець має рівно нуль очок."}},{"rule":"Кандора — закритий кан","value":"Відразу","tooltip":{"label":"Кандора — закритий кан","content":"Новий індикатор дори перевертається відразу після оголошення закритого кану"}},{"rule":"Кандора — відкритий кан","value":"Відразу","tooltip":{"label":"Кандора — відкритий кан","content":"Новий індикатор дори перевертається відразу після оголошення відкритого кану)"}},{"rule":"Закритий кан під час ріічі","value":"✅ (з обмеженнями)","tooltip":{"label":"Закритий кан під час ріічі","content":"Дозволено за двох умов:\n1. Тайл для кану витягнуто безпосередньо\n2. Очікування не змінюється після кану"}},{"rule":"Залишок ріічі депозитів","value":"1-му місцю"},{"rule":"Абортивні нічиї","value":"Відсутні","tooltip":{"label":"Абортивні нічиї","content":"Відсутні: Суфу ренда — 4 однакові вітри на першому скиді\nСукан наґаре — 4 кани різними гравцями\nКюшу кюхай — 9 різних благородних на першому ході\nСуча ріічі — усі 4 гравці оголосили ріічі"}},{"rule":"Санчахо (рон трьох)","value":"❌","tooltip":{"label":"Санчахо","content":"Потрійний рон (3 гравці оголошують рон одночасно) не призводить до абортивної нічиї. Усі три рони зараховуються."}},{"rule":"Пінфу","value":"Цумо 20 фу, Рон 30 фу","tooltip":{"label":"Пінфу","content":"Цумо: рахується як 20 фу (без 10 фу за цумо)\nРон: рахується як 30 фу"}},{"rule":"Чітойцу","value":"25 фу","tooltip":{"label":"Чітойцу","content":"Завжди 25 фу, незалежно від складу пар"}},{"rule":"Іппацу + Ріншян","value":"❌","tooltip":{"label":"Іппацу + Ріншян","content":"Іппацу та Хайтей не можуть комбінуватися з Ріншян кайхо"}},{"rule":"Кокуші — закритий кан","value":"✅","tooltip":{"label":"Кокуші — закритий кан","content":"Дозволено перехопити (рон) чужий закритий кан, якщо є готова рука на кокуші мусо"}},{"rule":"Чюрен — закритий кан","value":"❌","tooltip":{"label":"Чюрен — закритий кан","content":"Не дозволено перехоплювати чужий закритий кан для чюрен пото"}},{"rule":"Секінін бараі (пао)","value":"Дайсанґен, Дайсуші","tooltip":{"label":"Секінін бараі (пао)","content":"Відповідальність за виплату:\n— Дайсанґен: гравець, що віддав тайл для 3-го пону драконів\n— Дайсуші: гравець, що віддав тайл для 4-го понгу вітрів\n\nПри композитному якумані — відповідальність розділяється окремо за кожен якуман"}},{"rule":"Композитний якуман","value":"✅","tooltip":{"label":"Композитний якуман","content":"Дозволено комбінувати кілька якуманів в одній руці.\n\nОсобливість Тенхо: дилер починає з 14 тайлів, тому будь-який тайл може вважатися виграшним. Це означає, що Тенхо завжди комбінується з подвійними варіантами якуманів (Суанко танкі, Кокуші 13-wait, Чюрен 9-wait) = потрійний якуман."}}]}' WHERE id = 9;
UPDATE gameRules SET details = '{"rules":[{"rule":"Кількість гравців","value":"4"},{"rule":"Стартові очки","value":"30,000"},{"rule":"Мінімум ігор для рейтингу","value":"—"},{"rule":"Хонба","value":"3x500","tooltip":{"label":"Хонба","content":"Збільшена хонба: кожна паличка додає 500 очок замість стандартних 100"}},{"rule":"Червоні п''ятірки","value":"✅"},{"rule":"Пріоритет","value":"рон → пон/кан → чі","tooltip":{"label":"Пріоритет","content":"Рон завжди має пріоритет.\nПон і кан мають пріоритет над чі"}},{"rule":"Аґарі яме","value":"❌","tooltip":{"label":"Аґарі яме","content":"Гра продовжується до кінця ханчану (раунду), навіть якщо хтось з гравців досяг цільового рахунку."}},{"rule":"Банкрутство","value":"❌","tooltip":{"label":"Банкрутство","content":"≤ 0: Гра закінчується, коли рахунок гравця досягає нуля (або менше).\n\n< 0: Гра закінчується, коли рахунок гравця стає від''ємним. Гра продовжується, коли гравець має рівно нуль очок."}},{"rule":"Ріічі: мінімум 1000 очок","value":"❌","tooltip":{"label":"Ріічі: мінімум 1000 очок","content":"Можна річувати, навіть якщо у гравця менше 1000 очок або мінус"}},{"rule":"Округлення до манґану","value":"✅","tooltip":{"label":"Округлення до манґану","content":"4 хан 30 фу коштує як манґан"}},{"rule":"Підрахований якуман","value":"✅"},{"rule":"Накладання якуманів","value":"✅"},{"rule":"Ріічі без наступного ходу","value":"✅"},{"rule":"Наґаші манґан","value":"✅"},{"rule":"Наґаші манґан: зараховується як перемога","value":"❌"},{"rule":"Подвійне ріічі","value":"1️⃣➕1️⃣"},{"rule":"Великі вітри","value":"⭐⭐","tooltip":{"label":"Великі вітри","content":"Подвійний якуман при зборі всіх чотирьох вітрів"}},{"rule":"Тринадцять сиріт на 13 очікуваннях","value":"⭐⭐","tooltip":{"label":"Тринадцять сиріт","content":"Подвійний якуман при очікуванні на всі 13 тайлів"}},{"rule":"Дев''ять воріт на 9 очікуваннях","value":"⭐⭐","tooltip":{"label":"Дев''ять воріт","content":"Подвійний якуман при очікуванні на всі 9 тайлів"}},{"rule":"Чотири закриті триплети на парі","value":"⭐⭐","tooltip":{"label":"Чотири закриті триплети","content":"Подвійний якуман при зборі на парі"}},{"rule":"Подвійний вітер","value":"2 фу"},{"rule":"Ума","value":"15 / 5 / -5 / -15","tooltip":{"label":"Ума 15/5","content":"Фіксована ума:\n  15 / 5 / -5 / -15"}}]}' WHERE id = 10;
